    $$
    \begin{aligned}
        \frac{7 + x}{2} &= 1 \implies 7 + x = 2 \implies x = -5, \\
        \frac{12 + y}{2} &= 4 \implies 12 + y = 8 \implies y = -4.
    \end{aligned}
    $$
    $$
    \begin{aligned}
        D &= (-5, -4).
    \end{aligned}
    $$
    <answer>(-5, -4)</answer>

